  getDimension(aspect_ratio) {
    let width, height;
    if (aspect_ratio) {
      if (aspect_ratio === '1:1') {
        width = 1024;
        height = 1024;
      } else if (aspect_ratio === '3:2') {
        width = 1216;
        height = 832;
      } else if (aspect_ratio === '4:3') {
        width = 1152;
        height = 896;
      } else if (aspect_ratio === '5:4') {
        width = 1088;
        height = 896;
      } else if (aspect_ratio === '16:9') {
        width = 1344;
        height = 768;
      } else if (aspect_ratio === '21:9') {
        width = 1536;
        height = 640;
      } else if (aspect_ratio === '2:3') {
        width = 832;
        height = 1216;
      } else if (aspect_ratio === '3:4') {
        width = 896;
        height = 1152;
      } else if (aspect_ratio === '4:5') {
        width = 896;
        height = 1088;
      } else if (aspect_ratio === '9:19') {
        width = 768;
        height = 1344;
      } else if (aspect_ratio === '9:21') {
        width = 640;
        height = 1536;
      } else {
        width = 1344;
        height = 768;
      }
    } else {
      width = 1344;
      height = 768;
    }
    return {
      w: width,
      h: height
    };
  }

